.dbconfig defensive off
BEGIN;
PRAGMA writable_schema = on;
PRAGMA foreign_keys = off;
PRAGMA encoding = 'UTF-8';
PRAGMA page_size = '4096';
PRAGMA auto_vacuum = '0';
PRAGMA user_version = '0';
PRAGMA application_id = '0';
CREATE TABLE [bars_1m] (
   [symbol] TEXT,
   [datetime] TEXT,
   [open] FLOAT,
   [high] FLOAT,
   [low] FLOAT,
   [close] FLOAT,
   [volume] INTEGER,
   PRIMARY KEY ([symbol], [datetime])
);
CREATE TABLE [watchlist] (
   [symbol] TEXT PRIMARY KEY,
   [name] TEXT,
   [added_at] TEXT
, news_notify_count INTEGER DEFAULT 0);
CREATE TABLE [bars_1h] (
   [symbol] TEXT,
   [datetime] TEXT,
   [open] FLOAT,
   [high] FLOAT,
   [low] FLOAT,
   [close] FLOAT,
   [volume] INTEGER,
   PRIMARY KEY ([symbol], [datetime])
);
CREATE TABLE [bars_1d] (
   [symbol] TEXT,
   [date] TEXT,
   [open] FLOAT,
   [high] FLOAT,
   [low] FLOAT,
   [close] FLOAT,
   [volume] INTEGER,
   PRIMARY KEY ([symbol], [date])
);
CREATE TABLE [dismissed_notifications] (
   [notification_id] TEXT PRIMARY KEY,
   [dismissed_at] TEXT
);
CREATE TABLE [generated_notifications] (
   [id] TEXT PRIMARY KEY,
   [type] TEXT,
   [symbol] TEXT,
   [date] TEXT,
   [title] TEXT,
   [message] TEXT,
   [direction] TEXT,
   [percent_change] FLOAT,
   [created_at] TEXT
, articles_json TEXT DEFAULT '');
CREATE TABLE [news_briefing_articles] (
   [id] TEXT PRIMARY KEY,
   [symbol] TEXT,
   [url_hash] TEXT,
   [url] TEXT,
   [date] TEXT,
   [created_at] TEXT
);
CREATE TABLE [user_settings] (
   [id] INTEGER PRIMARY KEY,
   [email] TEXT,
   [email_confirmed] INTEGER,
   [email_notifications_enabled] INTEGER,
   [confirmation_code] TEXT,
   [updated_at] TEXT
);
CREATE TABLE [alerts] (
   [id] TEXT PRIMARY KEY,
   [reminder_id] TEXT,
   [ticker] TEXT,
   [message] TEXT,
   [triggered_at] TEXT,
   [is_read] INTEGER
);
CREATE TABLE [reminders] (
   [id] TEXT PRIMARY KEY,
   [original_text] TEXT,
   [ticker] TEXT,
   [company_name] TEXT,
   [action] TEXT,
   [status] TEXT,
   [condition_type] TEXT,
   [target_price] FLOAT,
   [percent_change] FLOAT,
   [trigger_time] TEXT,
   [custom_condition] TEXT,
   [created_at] TEXT,
   [triggered_at] TEXT,
   [current_price] FLOAT,
   [notes] TEXT
);
