pi/news?id=abbc86b537001e13d43d8a55dfe91c33ad8c1bd5bcecb5044fb30c563858fc87", "source": "Yahoo"}, {"headline": "Final Trades: Meta, IBM, CrowdStrike and the ICE U.S. Dollar Index", "summary": "The Investment Committee shares their top stocks to watch for the second half of the year, including Meta, IBM, and CrowdStrike. They also discuss the ICE U.S. Dollar Index. The committee provides their final trades for the period.", "url": "https://finnhub.io/api/news?id=0a5ee263d14f57544d1a419a2d58ec0ad5708e4cd9d312698da3fb7f0964610f", "source": "CNBC"}, {"headline": "Meta Stock Slides After Hundreds of Job Cuts", "summary": "Meta Platforms plans to cut a few hundred jobs across the company, including in its Reality Labs unit, as part of a restructuring effort. The job cuts will affect various teams, including social media, recruiting, and sales. Shares of Meta dipped 1.2% in early trading.", "url": "https://finnhub.io/api/news?id=53dcb3a0dd33cd5007eeeaa91898650e843744e12f2f5ea66e34b23659539131", "source": "Yahoo"}]');
